11	use ans_proto::ans::{
12	    ActionCheckRequest, ActionCheckResponse, ActionResult, BudgetConfig, BudgetConfigRequest,
13	    BudgetStatus, BudgetStatusRequest, CloseSessionRequest, CreateGoalRequest,
14	    CreateSessionRequest, DiffReport, DiffRequest, DistilledDom, DistractionList,
15	    DistractionRequest, DomRequest, Empty, ExecuteActionRequest, GoalState, GoalStateRequest,
16	    HealthStatus, InjectionScanRequest, InjectionScanResult, NavigateRequest, PageState,
17	    ProgressUpdate, QueryBestActionsRequest, RoutedSignal, ScoredActionList, ScreenshotRequest,
18	    ScreenshotResponse, SearchRequest, Session, SessionRequest, StoreScoreRequest,
19	    StoreScoreResponse, SubmitReportsRequest,
20	};
21	use tonic::{transport::Server, Request, Response, Status};
22	use tracing;
23	use uuid::Uuid;
24	
