38	// ── Public API ───────────────────────────────────────────────────────
39	
40	/// The gRPC server. Created once at daemon startup, runs until shutdown.
41	pub struct IpcServer {
42	    sessions: SessionManager,
43	    goals: GoalManager,
44	    events: Arc<EventBus>,
45	    decisions: ans_storage::DecisionStore,
46	    budget: std::sync::Arc<tokio::sync::Mutex<ans_budget::BudgetTracker>>,
47	    signal_router: SignalRouter,
48	}
49	
50	impl IpcServer {
51	    pub fn new() -> Self {
52	        Self {
53	            sessions: SessionManager::new(),
54	            goals: GoalManager::new(),
55	            events: Arc::new(EventBus::new()),
56	            decisions: ans_storage::DecisionStore::new(),
57	            budget: std::sync::Arc::new(tokio::sync::Mutex::new(
58	                ans_budget::BudgetTracker::default(),
59	            )),
60	            signal_router: SignalRouter::new(),
61	        }
62	    }
63	
64	    /// Start the gRPC server and block until shutdown signal received.
65	    pub async fn serve(self, addr: SocketAddr) -> Result<(), Box<dyn std::error::Error>> {
66	        let svc = AgentNervousSystemServer {
67	            sessions: self.sessions,
68	            goals: self.goals,
69	            events: self.events,
70	            decisions: self.decisions,
71	            budget: self.budget,
72	            signal_router: self.signal_router,
73	        };
74	
75	        tracing::info!("gRPC server starting on {}", addr);
76	
77	        Server::builder()
78	            .add_service(generated::AgentNervousSystemServer::new(svc))
79	            .serve_with_shutdown(addr, async {
80	                let _ = tokio::signal::ctrl_c().await;
81	                tracing::info!("Shutdown signal received");
82	            })
83	            .await?;
84	
85	        Ok(())
86	    }
87	}
88	
89	impl Default for IpcServer {
90	    fn default() -> Self {
91	        Self::new()
92	    }
93	}
