114	    async fn create_session(
115	        &self,
116	        request: Request<CreateSessionRequest>,
117	    ) -> Result<Response<Session>, Status> {
118	        let req = request.into_inner();
119	        let goal_id = parse_uuid(&req.goal_id, "goal_id")?;
120	        let start_url = optional_string(&req.start_url);
121	
122	        let session_id = self
123	            .sessions
124	            .create(goal_id, start_url)
125	            .await
126	            .map_err(|e| Status::internal(e.to_string()))?;
127	
128	        let now = now_epoch_ms();
129	        Ok(Response::new(Session {
130	            session_id: session_id.to_string(),
131	            goal_id: req.goal_id,
132	            status: "idle".into(),
133	            current_page: None,
134	            created_at: now,
135	            last_activity_at: now,
136	        }))
137	    }
