175	    async fn execute_action(
176	        &self,
177	        request: Request<ExecuteActionRequest>,
178	    ) -> Result<Response<ActionResult>, Status> {
179	        let req = request.into_inner();
180	        let session_id = parse_uuid(&req.session_id, "session_id")?;
181	
182	        let proto_action = req
183	            .action
184	            .ok_or_else(|| Status::invalid_argument("action is required"))?;
185	
186	        let action = proto_to_core_action(&proto_action)?;
187	
188	        let outcome = self
189	            .sessions
190	            .execute_action(session_id, &action)
191	            .await
192	            .map_err(|e| Status::internal(e.to_string()))?;
193	
194	        Ok(Response::new(ActionResult {
195	            success: outcome.success,
196	            error_message: outcome.error_message.unwrap_or_default(),
197	            new_state: None,
198	            diff: None,
199	            execution_time_ms: outcome.execution_time_ms as i64,
