255	    async fn compute_diff(
256	        &self,
257	        request: Request<DiffRequest>,
258	    ) -> Result<Response<DiffReport>, Status> {
259	        let req = request.into_inner();
260	        let before = req
261	            .before
262	            .ok_or_else(|| Status::invalid_argument("before is required"))?;
263	        let after = req
264	            .after
265	            .ok_or_else(|| Status::invalid_argument("after is required"))?;
266	
267	        let before_page = ans_distill::serialization::proto_to_distilled_page(&before);
268	        let after_page = ans_distill::serialization::proto_to_distilled_page(&after);
269	
270	        let differ = ans_diff::PageDiffer;
271	        let output = differ.diff(&before_page, &after_page);
272	
273	        Ok(Response::new(DiffReport {
274	            before_url: before_page.url,
275	            after_url: after_page.url,
276	            is_same_page: output.is_same_page,
277	            added: output
278	                .added
279	                .into_iter()
280	                .map(|c| ans_proto::ans::ElementChange {
281	                    tag: c.tag,
282	                    text: c.text,
283	                    selector: c.selector,
284	                    index: c.index,
285	                })
286	                .collect(),
287	            removed: output
288	                .removed
289	                .into_iter()
290	                .map(|c| ans_proto::ans::ElementChange {
291	                    tag: c.tag,
292	                    text: c.text,
293	                    selector: c.selector,
294	                    index: c.index,
295	                })
296	                .collect(),
297	            modified: output
298	                .modified
299	                .into_iter()
300	                .map(|m| ans_proto::ans::ElementModification {
301	                    selector: m.selector,
302	                    attribute_name: m.attribute_name,
303	                    old_value: m.old_value,
304	                    new_value: m.new_value,
305	                })
306	                .collect(),
307	            visual_diff_percentage: output.visual_diff_pct,
308	            summary: output.summary,
309	        }))
310	    }
