372	    type SubscribeGoalUpdatesStream = std::pin::Pin<
373	        Box<
374	            dyn tonic::codegen::tokio_stream::Stream<
375	                    Item = std::result::Result<ans_proto::ans::GoalUpdate, tonic::Status>,
376	                > + std::marker::Send,
377	        >,
378	    >;
