380	    async fn subscribe_goal_updates(
381	        &self,
382	        request: Request<GoalStateRequest>,
383	    ) -> Result<Response<Self::SubscribeGoalUpdatesStream>, Status> {
384	        let req = request.into_inner();
385	        let goal_id = if req.goal_id.is_empty() {
386	            None
387	        } else {
388	            Some(
389	                Uuid::parse_str(&req.goal_id)
390	                    .map_err(|_| Status::invalid_argument("invalid goal_id"))?,
391	            )
392	        };
393	
394	        let rx = self.goals.subscribe();
395	        let stream = BroadcastStream::new(rx).filter_map(move |result| {
396	            let gid = goal_id;
397	            let notification = result.ok()?;
398	            if gid.is_none_or(|id| notification.goal_id == id) {
399	                Some(Ok(ans_proto::ans::GoalUpdate {
400	                    goal_id: notification.goal_id.to_string(),
401	                    event_type: goal_status_event(&notification.status),
402	                    message: notification.message,
403	                    progress: notification.progress,
404	                    sub_goal: None,
405	                }))
406	            } else {
407	                None
408	            }
409	        });
410	
411	        Ok(Response::new(Box::pin(stream)))
412	    }
