416	    async fn submit_eye_reports(
417	        &self,
418	        request: Request<SubmitReportsRequest>,
419	    ) -> Result<Response<RoutedSignal>, Status> {
420	        let req = request.into_inner();
421	        let _session_id = parse_uuid(&req.session_id, "session_id")?;
422	
423	        // Publish each report to the event bus for subscribers
424	        for report in &req.reports {
425	            self.events.eye_reports.publish(EyeReportEvent {
426	                eye_name: report.eye_name.clone(),
427	                goal_id: Uuid::nil(),
428	                confidence: report.confidence,
429	                content: format_eye_content(&report.content),
430	            });
431	        }
432	
433	        // Convert proto reports → core reports, then route through SignalRouter
434	        let core_reports: Vec<ans_core::signal::EyeReport> = req
435	            .reports
436	            .iter()
437	            .filter_map(proto_to_core_eye_report)
438	            .collect();
439	
440	        let signal = self.signal_router.route(&core_reports);
441	
442	        Ok(Response::new(RoutedSignal {
443	            unified_perception: signal.unified_perception,
444	            alerts: signal
445	                .alerts
446	                .into_iter()
447	                .map(|a| ans_proto::ans::DistractionAlert {
448	                    kind: a.kind,
449	                    description: a.description,
450	                    action_taken: a.action_taken,
451	                })
452	                .collect(),
453	            confidence: signal.confidence,
454	            recommended_action_hint: signal.recommended_action_hint.unwrap_or_default(),
455	            contradictions: signal.contradictions,
456	        }))
457	    }
