486	    // ── Immune System ────────────────────────────────────────────────
487	
488	    async fn classify_distractions(
489	        &self,
490	        request: Request<DistractionRequest>,
491	    ) -> Result<Response<DistractionList>, Status> {
492	        let req = request.into_inner();
493	        let url = req.url;
494	        let css_hints = String::new(); // DOM attribute scan deferred — content rules cover most cases
495	
496	        // Extract all visible text from the distilled DOM for content scanning
497	        let dom_text = req
498	            .dom
499	            .as_ref()
500	            .map(|dom| {
501	                dom.elements
502	                    .iter()
503	                    .map(|el| el.text.as_str())
504	                    .collect::<Vec<_>>()
505	                    .join(" ")
506	            })
507	            .unwrap_or_default();
508	
509	        let classifier = ans_immune::DistractionClassifier;
510	        let flags = classifier.classify(&url, &dom_text, &css_hints);
511	
512	        let distractions: Vec<_> = flags
513	            .iter()
514	            .map(ans_immune::serialization::distraction_to_proto_list_item)
515	            .collect();
516	
517	        Ok(Response::new(DistractionList {
518	            distractions,
519	            classification_time_us: 0,
520	        }))
521	    }
522	
523	    async fn scan_injections(
524	        &self,
525	        request: Request<InjectionScanRequest>,
526	    ) -> Result<Response<InjectionScanResult>, Status> {
527	        let req = request.into_inner();
528	
529	        let detector = ans_immune::InjectionDetector;
530	        let start = std::time::Instant::now();
531	        let result = detector.scan(&req.url, &req.page_content);
532	        let scan_time_us = start.elapsed().as_micros() as i64;
533	
534	        let mut proto = ans_immune::serialization::injection_result_to_proto(&result);
535	        proto.scan_time_us = scan_time_us;
536	
537	        Ok(Response::new(proto))
538	    }
539	
540	    async fn check_action(
541	        &self,
542	        request: Request<ActionCheckRequest>,
543	    ) -> Result<Response<ActionCheckResponse>, Status> {
544	        let req = request.into_inner();
545	        let session_id = parse_uuid(&req.session_id, "session_id")?;
546	
547	        // Get current URL for context
548	        let url = self.sessions.get_url(session_id).await.unwrap_or_default();
549	
550	        // Build scannable text from the action itself
551	        let action = req.action.as_ref();
552	        let action_text = action.map_or(String::new(), |a| {
553	            format!("{} {} {}", a.action_type, a.selector, a.value)
554	        });
555	
556	        // Run both immune checks
557	        let classifier = ans_immune::DistractionClassifier;
558	        let distractions = classifier.classify(&url, &action_text, &action_text);
559	
560	        let detector = ans_immune::InjectionDetector;
561	        let injection = detector.scan(&url, &action_text);
562	
563	        let response =
564	            ans_immune::serialization::build_action_check_response(&distractions, &injection);
565	
566	        Ok(Response::new(response))
567	    }
