1	//! Session manager for goal-scoped browser sessions.
2	//!
3	//! Each session wraps a [`CdpBackend`] (Chromium instance) and is
4	//! identified by a UUID. Sessions are organized by goal — not by tab —
5	//! and share the same goal state store.
6	
7	use std::collections::HashMap;
8	use std::sync::Arc;
9	use std::time::Duration;
10	
11	use ans_cdp::CdpBackend;
12	use ans_core::backend::{BrowserBackend, BrowserError, ImageFormat, PageState};
13	use ans_core::distill::{DistillMode, DistilledPage};
14	use ans_core::session::{Action, ActionOutcome, SessionStatus};
15	use tokio::sync::RwLock;
16	use tracing;
17	use uuid::Uuid;
18	
19	/// Handle to an active browser session.
20	pub struct SessionHandle {
21	    pub session_id: Uuid,
22	    pub goal_id: Uuid,
23	    pub backend: CdpBackend,
24	    pub current_url: String,
25	    pub status: SessionStatus,
26	}
27	
28	/// Thread-safe session registry.
29	///
30	/// Cloning shares the underlying `Arc<RwLock<>>` — all references
31	/// see the same sessions.
32	#[derive(Clone)]
33	pub struct SessionManager {
34	    sessions: Arc<RwLock<HashMap<Uuid, SessionHandle>>>,
35	}
36	
37	impl Default for SessionManager {
38	    fn default() -> Self {
39	        Self::new()
40	    }
41	}
42	
43	impl SessionManager {
44	    pub fn new() -> Self {
45	        Self {
46	            sessions: Arc::new(RwLock::new(HashMap::new())),
47	        }
48	    }
49	
50	    /// Create a new session by launching a Chromium instance.
51	    /// If `start_url` is provided, navigate to it immediately.
52	    pub async fn create(
53	        &self,
54	        goal_id: Uuid,
55	        start_url: Option<String>,
56	    ) -> Result<Uuid, BrowserError> {
57	        let session_id = Uuid::new_v4();
58	        tracing::info!(%session_id, %goal_id, "Creating session");
59	
60	        let backend = CdpBackend::launch().await?;
61	
62	        if let Some(url) = &start_url {
63	            let _ = backend
64	                .navigate(url, Duration::from_secs(30))
65	                .await
66	                .map(|state| {
67	                    tracing::info!(url = %state.url, "Session started at URL");
68	                });
69	        }
70	
71	        let handle = SessionHandle {
72	            session_id,
73	            goal_id,
74	            backend,
75	            current_url: start_url.unwrap_or_else(|| "about:blank".into()),
76	            status: SessionStatus::Idle,
77	        };
78	
79	        self.sessions.write().await.insert(session_id, handle);
80	
81	        Ok(session_id)
82	    }
83	
84	    /// Close a session and kill its Chromium process.
85	    pub async fn close(&self, session_id: Uuid) -> Result<(), BrowserError> {
86	        tracing::info!(%session_id, "Closing session");
87	        if let Some(handle) = self.sessions.write().await.remove(&session_id) {
88	            handle.backend.close().await?;
89	        }
90	        Ok(())
91	    }
92	
93	    /// Close all active sessions.
94	    pub async fn close_all(&self) {
95	        let ids: Vec<Uuid> = self.sessions.read().await.keys().copied().collect();
96	        for id in ids {
97	            let _ = self.close(id).await;
98	        }
99	        tracing::info!("All sessions closed");
100	    }

