1	//! CDP WebSocket client implementing [`ans_core::BrowserBackend`].
2	//!
3	//! Architecture:
4	//! ```text
5	//! CdpBackend
6	//!   ├── ChromiumProcess (owns child process)
7	//!   └── CdpConnection
8	//!         ├── write_tx: mpsc::Sender<String>  (outgoing commands)
9	//!         ├── pending: Arc<Mutex<HashMap<id, oneshot::Sender>>>
10	//!         └── reader task (spawned, reads WS messages)
11	//! ```
12	
13	use std::collections::HashMap;
14	use std::sync::Arc;
15	use std::time::Duration;
16	
17	use ans_core::backend::{BrowserError, ImageFormat, PageState};
18	use ans_core::distill::{DistillMode, DistilledPage};
19	use ans_core::session::ActionOutcome;
20	use async_trait::async_trait;
21	use futures_util::{SinkExt, StreamExt};
22	use tokio::sync::{mpsc, oneshot, Mutex};
23	use tokio_tungstenite::tungstenite::Message;
24	use tracing;
25	
26	use crate::command::{self, CdpCommand, CdpError, CdpMessage};
27	use crate::process::ChromiumProcess;
28	
29	// ── CdpConnection ────────────────────────────────────────────────────
30	
31	type PendingMap = Arc<Mutex<HashMap<i64, oneshot::Sender<Result<serde_json::Value, CdpError>>>>>;
32	
33	struct CdpConnection {
34	    write_tx: mpsc::Sender<String>,
35	    pending: PendingMap,
36	}
37	
38	impl CdpConnection {
39	    /// Establish a WebSocket connection and spawn the reader task.
40	    async fn connect(debug_url: &str) -> Result<Self, BrowserError> {
41	        let (ws, _) = tokio_tungstenite::connect_async(debug_url)
42	            .await
43	            .map_err(|e| BrowserError::ConnectionLost(e.to_string()))?;
44	
45	        let (mut write, read) = ws.split();
46	        let (write_tx, mut write_rx) = mpsc::channel::<String>(256);
47	        let pending: PendingMap = Arc::new(Mutex::new(HashMap::new()));
48	
49	        // Writer task: pumps messages from the mpsc channel to the WebSocket
50	        let writer_pending = pending.clone();
51	        tokio::spawn(async move {
52	            while let Some(msg) = write_rx.recv().await {
53	                if let Err(e) = write.send(Message::Text(msg)).await {
54	                    let _ = writer_pending.lock().await;
55	                    tracing::error!(?e, "CDP write failed");
56	                    break;
