102	    /// Execute an action on a session.
103	    pub async fn execute_action(
104	        &self,
105	        session_id: Uuid,
106	        action: &Action,
107	    ) -> Result<ActionOutcome, BrowserError> {
108	        let sessions = self.sessions.read().await;
109	        let handle = sessions
110	            .get(&session_id)
111	            .ok_or(BrowserError::BrowserClosed)?;
112	
113	        let outcome = match action.action_type {
114	            ans_core::session::ActionType::Click => {
115	                let selector = action
116	                    .selector
117	                    .as_deref()
118	                    .ok_or_else(|| BrowserError::SelectorNotFound("missing selector".into()))?;
119	                handle.backend.click(selector).await?
120	            }
121	            ans_core::session::ActionType::Type => {
122	                let selector = action
123	                    .selector
124	                    .as_deref()
125	                    .ok_or_else(|| BrowserError::SelectorNotFound("missing selector".into()))?;
126	                let text = action.value.as_deref().unwrap_or("");
127	                handle.backend.type_text(selector, text).await?
128	            }
129	            ans_core::session::ActionType::Scroll => {
130	                let pixels = action.value.as_deref().and_then(|v| v.parse().ok());
131	                let selector = action.selector.as_deref();
132	                handle.backend.scroll(pixels, selector).await?
133	            }
134	            ans_core::session::ActionType::Select => {
135	                let selector = action
136	                    .selector
137	                    .as_deref()
138	                    .ok_or_else(|| BrowserError::SelectorNotFound("missing selector".into()))?;
139	                let value = action.value.as_deref().unwrap_or("");
140	                handle.backend.select_option(selector, value).await?
141	            }
142	            ans_core::session::ActionType::Navigate => {
143	                let url = action
144	                    .value
145	                    .as_deref()
146	                    .ok_or_else(|| BrowserError::CdpProtocol("missing URL".into()))?;
147	                let state = handle
148	                    .backend
149	                    .navigate(url, Duration::from_secs(30))
150	                    .await?;
151	                ActionOutcome {
152	                    success: true,
153	                    error_message: None,
154	                    execution_time_ms: 0,
155	                    page_url_after: Some(state.url),
156	                    dom_changed: false,
157	                }
158	            }
159	            ans_core::session::ActionType::Wait => {
160	                let ms = action
161	                    .value
162	                    .as_deref()
163	                    .and_then(|v| v.parse().ok())
164	                    .unwrap_or(1000u64);
165	                tokio::time::sleep(Duration::from_millis(ms)).await;
166	                ActionOutcome {
167	                    success: true,
168	                    error_message: None,
169	                    execution_time_ms: ms,
170	                    page_url_after: None,
171	                    dom_changed: false,
172	                }
173	            }
174	            ans_core::session::ActionType::Submit => {
175	                // Submit is typically handled as a click on a submit button
176	                // or pressing Enter. Evaluate a JS submit on the form.
177	                let selector = action.selector.as_deref().unwrap_or("form");
178	                let result = handle
179	                    .backend
180	                    .execute_script(&format!(
181	                        "(function(){{var f=document.querySelector('{}');if(f){{f.submit();return'ok'}}return'not found'}})()",
182	                        escape_for_js(selector)
183	                    ))
184	                    .await?;
185	                ActionOutcome {
186	                    success: result.contains("ok"),
187	                    error_message: if result.contains("ok") {
188	                        None
189	                    } else {
190	                        Some("form not found".into())
191	                    },
192	                    execution_time_ms: 0,
193	                    page_url_after: None,
194	                    dom_changed: true,
195	                }
196	            }
197	            ans_core::session::ActionType::Screenshot => {
198	                let _bytes = handle
199	                    .backend
200	                    .capture_screenshot(ans_core::backend::ImageFormat::Png, false)
201	                    .await?;
202	                ActionOutcome {
203	                    success: true,
204	                    error_message: None,
205	                    execution_time_ms: 0,
206	                    page_url_after: None,
207	                    dom_changed: false,
208	                }
209	            }
210	        };
211	
212	        Ok(outcome)
213	    }
