1	//! Decision record CRUD and vector search.
2	//!
3	//! In-memory store with cosine similarity search. LanceDB integration
4	//! with IVF_PQ index is deferred to a future phase when Arrow/Lance
5	//! columnar storage is fully wired.
6	
7	use std::sync::RwLock;
8	
9	use ans_core::decision::DecisionRecord;
10	
11	/// Thread-safe in-memory decision store with vector similarity search.
12	pub struct DecisionStore {
13	    records: RwLock<Vec<DecisionRecord>>,
14	}
15	
16	impl DecisionStore {
17	    /// Create a new empty decision store.
18	    pub fn new() -> Self {
19	        Self {
20	            records: RwLock::new(Vec::new()),
21	        }
22	    }
23	
24	    /// Insert a decision record. Returns the total count after insert.
25	    pub fn insert(&self, record: DecisionRecord) -> usize {
26	        let mut records = self.records.write().unwrap();
27	        records.push(record);
28	        records.len()
29	    }
30	
31	    /// Total number of stored records.
32	    pub fn len(&self) -> usize {
33	        self.records.read().unwrap().len()
34	    }
35	
36	    /// Whether the store is empty.
37	    pub fn is_empty(&self) -> bool {
38	        self.len() == 0
39	    }
40	
41	    /// Query top-k decisions by cosine similarity to the given embedding.
42	    /// Returns records sorted by similarity descending, filtered by min_score.
43	    pub fn query_similar(
44	        &self,
45	        embedding: &[f32],
46	        k: usize,
47	        min_score: f32,
48	    ) -> Vec<(DecisionRecord, f32)> {
49	        let records = self.records.read().unwrap();
50	        if records.is_empty() {
51	            return Vec::new();
52	        }
53	
54	        let mut scored: Vec<(usize, f32)> = records
55	            .iter()
56	            .enumerate()
57	            .filter_map(|(i, r)| {
58	                let sim = cosine_similarity(embedding, &r.context_embedding);
59	                if sim >= min_score {
60	                    Some((i, sim))
61	                } else {
62	                    None
63	                }
64	            })
65	            .collect();
66	
67	        // Sort descending by similarity
68	        scored.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap_or(std::cmp::Ordering::Equal));
69	
70	        scored
71	            .into_iter()
72	            .take(k)
73	            .map(|(i, sim)| (records[i].clone(), sim))
74	            .collect()
75	    }
76	}
77	
78	impl Default for DecisionStore {
79	    fn default() -> Self {
80	        Self::new()
81	    }
82	}
83	
84	/// Cosine similarity between two vectors.
85	fn cosine_similarity(a: &[f32], b: &[f32]) -> f32 {
86	    if a.is_empty() || b.is_empty() {
87	        return 0.0;
88	    }
89	
90	    let min_len = a.len().min(b.len());
91	    let mut dot = 0.0f32;
92	    let mut norm_a = 0.0f32;
93	    let mut norm_b = 0.0f32;
94	
95	    for i in 0..min_len {
96	        dot += a[i] * b[i];
97	        norm_a += a[i] * a[i];
98	        norm_b += b[i] * b[i];
99	    }
100

1	//! Heuristic distraction classifier.
2	//!
3	//! Runs at intake, before any eye perceives content. Three-stage pipeline:
4	//! 1. URL patterns — ad/tracking domains, redirect detection
5	//! 2. DOM content patterns — cookie banners, newsletter modals, surveys
6	//! 3. CSS class/id hints — overlay, popup, ad-related selectors
7	//!
8	//! Target: <1ms classification time for typical pages (5000 elements).
