16	
17	impl DistractionClassifier {
18	    /// Classify all distractions on a page.
19	    ///
20	    /// `dom_text` should be all visible text from the distilled DOM,
21	    /// concatenated for pattern matching. `css_hints` is the raw HTML
22	    /// snippet or attribute strings for class/id pattern matching.
23	    pub fn classify(&self, url: &str, dom_text: &str, css_hints: &str) -> Vec<DistractionFlag> {
24	        let mut flags = Vec::new();
25	
26	        // Stage 1: URL-based rules
27	        for rule in &rules::url_rules() {
28	            if rule.pattern.is_match(url) {
29	                flags.push(flag_from_rule(rule));
30	            }
31	        }
32	
33	        // Stage 2: Content-based rules
34	        for rule in &rules::content_rules() {
35	            if rule.pattern.is_match(dom_text) {
36	                flags.push(flag_from_rule(rule));
37	            }
38	        }
39	
40	        // Stage 3: CSS class/id hint rules
41	        for rule in &rules::css_hint_rules() {
42	            if rule.pattern.is_match(css_hints) {
43	                flags.push(flag_from_rule(rule));
44	            }
45	        }
46	
47	        // Deduplicate by kind, keeping the higher confidence
48	        deduplicate(&mut flags);
49	
50	        flags
51	    }
52	}
