1	//! Prompt injection detector.
2	//!
3	//! Scans page content for instruction-override attacks. Pipeline:
4	//! 1. Zero-width character scan
5	//! 2. Homoglyph detection
6	//! 3. Hidden content detection (display:none, visibility:hidden, aria-label traps)
7	//! 4. Instruction-override pattern matching
8	//!
9	//! Produces a score 0.0 (safe) to 1.0 (definite injection).
10	//! Target: <5ms scan time for typical pages.
11	
12	use ans_core::immune::{InjectionAction, InjectionFlag, InjectionLocation, InjectionScanResult};
13	
14	use crate::rules::{self};
15	
16	/// The prompt injection detector.
17	pub struct InjectionDetector;
18	
19	impl InjectionDetector {
20	    /// Scan page content for injection attempts.
21	    ///
22	    /// `url` provides context (some attacks are URL-specific).
23	    /// `raw_content` is the full page text: visible text + attributes + hidden content.
24	    pub fn scan(&self, url: &str, raw_content: &str) -> InjectionScanResult {
25	        let start = std::time::Instant::now();
26	        let mut flagged: Vec<InjectionFlag> = Vec::new();
27	        let mut max_score: f32 = 0.0;
28	
29	        // ── Stage 1: Zero-width characters ──────────────────────
30	        let zw_chars = rules::contains_zero_width_chars(raw_content);
31	        if !zw_chars.is_empty() {
32	            let snippet: String = zw_chars.iter().take(10).map(|(c, _)| *c).collect();
33	            max_score = max_score.max(0.7);
34	            flagged.push(InjectionFlag {
35	                content_snippet: snippet,
36	                pattern_matched: format!("{} zero-width characters detected", zw_chars.len()),
37	                location: InjectionLocation::ZeroWidthChars,
38	                confidence: 0.8,
39	            });
40	        }
41	
42	        // ── Stage 2: Homoglyph detection ────────────────────────
43	        let h_score = rules::homoglyph_score(raw_content);
44	        if h_score > 0.2 {
45	            let snippets = rules::find_homoglyphs(raw_content);
46	            if !snippets.is_empty() {
